module comparator(a, b, gte, eq, gt);
input [7:0] a, b;
output gte, eq, gt;
reg gte, eq, gt;

always@(a or b) begin
    if (a < b) begin
        gte = 1;
        eq = 0;
        gt = 0;
    end
    else if (a == b) begin
        gte = 0;
        eq = 1;
        gt = 0;
    end
    else begin
        gte = 0;
        eq = 0;
        gt = 1;
    end
end

endmodule
